import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';
import '../../styles/storekeeper/storekeeper-dashboard.css';
import api from '../../services/api';

const StorekeeperDashboard = () => {
  const [dashboard, setDashboard] = useState({
    balance: [],
    summary: {},
    lowStock: [],
    transactions: [],
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchDashboardData();
  }, []);

  const fetchDashboardData = async () => {
    try {
      setLoading(true);
      const [balanceRes, summaryRes, lowStockRes, importsRes, exportsRes] = await Promise.all([
        api.get('/inventory/balance'),
        api.get('/inventory/summary'),
        api.get('/inventory/low-stock'),
        api.get('/inventory/imports'),
        api.get('/inventory/exports'),
      ]);

      const imports = (importsRes.data?.data || []).map((row) => ({
        id: row.import_id,
        product_code: row.product_code,
        product_name: row.product_name,
        quantity: row.quantity,
        unit: row.unit,
        type: 'IMPORT',
        date: row.import_date,
      }));

      const exports = (exportsRes.data?.data || []).map((row) => ({
        id: row.export_id,
        product_code: row.product_code,
        product_name: row.product_name,
        quantity: row.quantity,
        unit: row.unit,
        type: 'EXPORT',
        date: row.export_date,
      }));

      const transactions = [...imports, ...exports]
        .sort((a, b) => new Date(b.date) - new Date(a.date))
        .slice(0, 10);

      setDashboard({
        balance: balanceRes.data?.data || [],
        summary: summaryRes.data?.data || {},
        lowStock: lowStockRes.data?.data || [],
        transactions,
      });

      setError(null);
    } catch (err) {
      console.error('Loi khi tai du lieu dashboard:', err);
      setError('Khong the tai du lieu dashboard. Vui long thu lai.');
    } finally {
      setLoading(false);
    }
  };

  const summary = dashboard.summary || {};

  if (loading) {
    return <div className="storekeeper-dashboard__loading">Dang tai du lieu...</div>;
  }

  if (error) {
    return (
      <div className="storekeeper-dashboard__error">
        <p>{error}</p>
        <button onClick={fetchDashboardData}>Thu lai</button>
      </div>
    );
  }

  return (
    <div className="storekeeper-dashboard">
      <div className="storekeeper-dashboard__header">
        <h1>Dashboard kho hang</h1>
        <p>Quan ly hang hoa, nhap xuat va canh bao ton kho</p>
      </div>

      <div className="storekeeper-dashboard__stats-grid">
        <div className="stat-card">
          <div className="stat-card__title">Tong san pham</div>
          <div className="stat-card__value">{Number(summary.total_products || 0).toLocaleString('vi-VN')}</div>
        </div>
        <div className="stat-card">
          <div className="stat-card__title">Tong danh muc</div>
          <div className="stat-card__value">{Number(summary.total_categories || 0).toLocaleString('vi-VN')}</div>
        </div>
        <div className="stat-card">
          <div className="stat-card__title">Tong so luong ton</div>
          <div className="stat-card__value">{Number(summary.total_quantity || 0).toLocaleString('vi-VN')}</div>
        </div>
        <div className="stat-card">
          <div className="stat-card__title">Canh bao ton kho</div>
          <div className="stat-card__value">{dashboard.lowStock.length.toLocaleString('vi-VN')}</div>
        </div>
      </div>

      <div className="storekeeper-dashboard__section">
        <div className="storekeeper-dashboard__section-header">
          <h2>Top san pham ton thap</h2>
          <Link to="/storekeeper/alerts" className="storekeeper-dashboard__link">Xem chi tiet</Link>
        </div>
        <div className="storekeeper-dashboard__table-wrap">
          <table className="storekeeper-dashboard__table">
            <thead>
              <tr>
                <th>Ma</th>
                <th>Ten san pham</th>
                <th>Danh muc</th>
                <th>So luong ton</th>
                <th>Don vi</th>
              </tr>
            </thead>
            <tbody>
              {dashboard.lowStock.slice(0, 10).map((item) => (
                <tr key={item.product_id}>
                  <td>{item.product_code}</td>
                  <td>{item.product_name}</td>
                  <td>{item.category_name || '-'}</td>
                  <td>{Number(item.stock_quantity || 0).toLocaleString('vi-VN')}</td>
                  <td>{item.unit || '-'}</td>
                </tr>
              ))}
              {dashboard.lowStock.length === 0 && (
                <tr>
                  <td colSpan="5" className="storekeeper-dashboard__empty">Khong co du lieu</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="storekeeper-dashboard__section">
        <div className="storekeeper-dashboard__section-header">
          <h2>Giao dich gan day</h2>
          <div className="storekeeper-dashboard__quick-links">
            <Link to="/storekeeper/imports" className="storekeeper-dashboard__link">Nhap kho</Link>
            <Link to="/storekeeper/exports" className="storekeeper-dashboard__link">Xuat kho</Link>
          </div>
        </div>
        <div className="storekeeper-dashboard__table-wrap">
          <table className="storekeeper-dashboard__table">
            <thead>
              <tr>
                <th>Ngay</th>
                <th>Loai</th>
                <th>Ma</th>
                <th>Ten san pham</th>
                <th>So luong</th>
              </tr>
            </thead>
            <tbody>
              {dashboard.transactions.map((tx) => (
                <tr key={`${tx.type}-${tx.id}`}>
                  <td>{new Date(tx.date).toLocaleDateString('vi-VN')}</td>
                  <td>{tx.type}</td>
                  <td>{tx.product_code}</td>
                  <td>{tx.product_name}</td>
                  <td>{Number(tx.quantity || 0).toLocaleString('vi-VN')} {tx.unit || ''}</td>
                </tr>
              ))}
              {dashboard.transactions.length === 0 && (
                <tr>
                  <td colSpan="5" className="storekeeper-dashboard__empty">Chua co giao dich</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default StorekeeperDashboard;
